import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../App';
import './AuthPages.css';

export default function LoginPage() {
  const { login, addToast } = useAuth();
  const navigate = useNavigate();
  const [form, setForm] = useState({ username: '', password: '' });
  const [errors, setErrors] = useState({});
  const [loading, setLoading] = useState(false);

  const validate = () => {
    const e = {};
    if (!form.username.trim()) e.username = 'Username is required';
    if (!form.password) e.password = 'Password is required';
    return e;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    const errs = validate();
    if (Object.keys(errs).length) { setErrors(errs); return; }
    setLoading(true);
    // Simulate API call
    await new Promise(r => setTimeout(r, 700));
    login({ username: form.username, firstName: form.username, lastName: '' });
    addToast('Welcome back!', 'success');
    navigate('/');
    setLoading(false);
  };

  const handleChange = (field) => (e) => {
    setForm(prev => ({ ...prev, [field]: e.target.value }));
    if (errors[field]) setErrors(prev => ({ ...prev, [field]: null }));
  };

  return (
    <div className="auth-page">
      <div className="auth-card">
        <div className="auth-header">
          <div className="auth-icon" aria-hidden="true">🔐</div>
          <h1>Welcome back</h1>
          <p>Sign in to your FOSSEE account</p>
        </div>

        <form onSubmit={handleSubmit} noValidate>
          <div className="form-group">
            <label className="form-label" htmlFor="username">Username</label>
            <input
              id="username"
              className={`form-control${errors.username ? ' form-control-error' : ''}`}
              type="text"
              value={form.username}
              onChange={handleChange('username')}
              placeholder="Enter your username"
              autoComplete="username"
              aria-describedby={errors.username ? 'username-error' : undefined}
              aria-invalid={!!errors.username}
            />
            {errors.username && (
              <span className="form-error" id="username-error" role="alert">{errors.username}</span>
            )}
          </div>

          <div className="form-group">
            <div className="form-label-row">
              <label className="form-label" htmlFor="password">Password</label>
              <Link to="/forgot-password" className="form-label-link">Forgot password?</Link>
            </div>
            <input
              id="password"
              className={`form-control${errors.password ? ' form-control-error' : ''}`}
              type="password"
              value={form.password}
              onChange={handleChange('password')}
              placeholder="Enter your password"
              autoComplete="current-password"
              aria-describedby={errors.password ? 'password-error' : undefined}
              aria-invalid={!!errors.password}
            />
            {errors.password && (
              <span className="form-error" id="password-error" role="alert">{errors.password}</span>
            )}
          </div>

          <button
            type="submit"
            className="btn btn-primary"
            style={{ width: '100%', marginTop: '8px' }}
            disabled={loading}
          >
            {loading ? (
              <>
                <span className="spinner" aria-hidden="true"></span>
                Signing in…
              </>
            ) : 'Sign in'}
          </button>
        </form>

        <div className="auth-footer">
          <p>New to FOSSEE Workshops? <Link to="/register">Create an account</Link></p>
        </div>
      </div>
    </div>
  );
}
